/**
 * Calculate the prorated charge when a user upgrades mid-billing cycle.
 *
 * @param currentPlan - The plan the user is currently on
 * @param newPlan - The plan the user is upgrading to
 * @param daysRemaining - Days left in the current billing cycle
 * @returns The prorated amount in cents (never negative)
 * @throws {InvalidPlanError} If newPlan costs less than currentPlan
 *
 * @example
 * ```ts
 * const charge = calculateProration(
 *   { id: 'basic', priceInCents: 1000 },
 *   { id: 'pro', priceInCents: 3000 },
 *   15
 * );
 * // charge === 985 (cents)
 * ```
 */
export function calculateProration(
  currentPlan: Plan,
  newPlan: Plan,
  daysRemaining: number
): number {
  if (newPlan.priceInCents < currentPlan.priceInCents) {
    throw new InvalidPlanError('Use calculateRefund() for downgrades');
  }
  const dailyDiff = (newPlan.priceInCents - currentPlan.priceInCents) / 30;
  return Math.max(0, Math.round(dailyDiff * daysRemaining));
}
